//
import { each, isArray, isObject, pick } from '../utils/zcutils';

function scanMark(parser) {
    let cache = { _name: {}, dependency: {}, as: {} };
    loopMark(parser, cache);

    each(cache.dependency, (value, prop) => cache.dependency[prop].push(cache._name[prop]));

    delete cache._name;
    return cache;
}

function loopMark(parser, cache, level = 0) {
    if (!parser) { return };
    let { children, name, dependency, as } = parser;

    parser._level = level;
    if (isArray(parser)) {
        parser.forEach((children, i) => loopMark(children, cache, level + '_' + i));
    }

    if (name) {
        cache._name[name] = parser;
    }

    if (dependency) {
        cache.dependency[isObject(dependency) ? dependency.name : dependency] = [];
    }

    if (as) {
        let unNamed = 'zcUnNamed';
        cache.as[pick(name, unNamed)] = cache.as[pick(name, unNamed)] || [];
        cache.as[pick(name, unNamed)].push(parser);

        cache.as[unNamed] = cache.as[unNamed] || [];
        cache.as[unNamed].push(parser);
    }

    if (children && children.length) {
        children.forEach((_, i) => loopMark(_, cache, level + '_' + i));
    }
}

export { scanMark };
